### LEVEL4_iotcl
`ioctl` 是 **Input/Output Control（输入/输出控制）** 的缩写。它是 Linux 和 Unix 系统中一个非常强大且通用的系统调用（System Call）。

+ ioctl 就像是发送控制指令。当你除了传输数据外，还想让驱动程序执行某些特定操作、调整设备状态、或者执行某个特定函数时，就会使用 ioctl。

```c
__int64 __fastcall device_ioctl(file *file, unsigned int cmd, unsigned __int64 arg)
{
    __int64 result; // rax
    int v5; // r8d
    char password[16]; // [rsp+0h] [rbp-28h] BYREF
    unsigned __int64 v7; // [rsp+10h] [rbp-18h]

    v7 = __readgsqword(0x28u);
    printk(&unk_D78);
    result = -1;
    if ( cmd == 1337 )
    {
        copy_from_user(password, arg, 16);
        v5 = strncmp(password, "hacvtgrjhlscihpk", 0x10u);
        result = 0;
        if ( !v5 )
        {
            win();
            return 0;
        }
    }
    return result;
}
```

#### EXP
```c
#include <stdio.h>
#include <stdlib.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <sys/ioctl.h> 

#define PATH "/proc/pwncollege"
#define CMD 1337

int main(){
    int fd;
    char *password = "hacvtgrjhlscihpk";
    ssize_t written;

    fd = open(PATH, O_WRONLY);
    written = ioctl(fd, CMD, password);
    printf("successfully");
    system("id");
    system("cat /flag");
    close(fd);

    return EXIT_SUCCESS;
}
```

