#### \_flags 规则：

\_flag 是 \_IO\_FILE 结构体中的第一个成员变量，这个成员变量在利用 \_IO\_2\_1\_stdoue 泄露 libc 的时候很重要。

\_flag 的高两位字节是由 libc 规定的，不同的 libc 可能存在差异，但基本上都是 0xfbad0000。

高两位字节的作用是作为一个标识，表示这是一个什么文件。而低两位的位数则决定了程序的运行状态：

#### \_flags 低两位的规则如下：

```c
#define _IO_MAGIC       0xFBAD0000  // 文件流结构体的魔数
#define _OLD_STDIO_MAGIC 0xFABC0000 // 旧版 stdio 的魔数（兼容用）
#define _IO_MAGIC_MASK  0xFFFF0000  // 魔数掩码（提取高 16 位）
#define _IO_USER_BUF   1   // 用户自定义缓冲区（关闭时不释放）
#define _IO_UNBUFFERED 2   // 无缓冲模式（直接操作文件描述符）
#define _IO_NO_READS   4   // 禁止读操作（只写模式）
#define _IO_NO_WRITES  8   // 禁止写操作（只读模式）
#define _IO_EOF_SEEN   0x10  // 已检测到文件结束符（EOF）
#define _IO_ERR_SEEN   0x20  // 发生 I/O 错误（如磁盘故障）
#define _IO_BAD_SEEN   0x4000 // 流处于不可恢复的错误状态
#define _IO_DELETE_DONT_CLOSE 0x40  // 关闭时不调用 close(_fileno)
#define _IO_LINKED            0x80  // 与其他流链接（共享缓冲区）
#define _IO_IN_BACKUP         0x100 // 正在备份数据（如内存映射回写）
#define _IO_LINE_BUF          0x200 // 行缓冲模式（遇到 '\n' 刷新）
#define _IO_TIED_PUT_GET      0x400 // 读写指针逻辑绑定（如 fgetpos/fsetpos）
#define _IO_CURRENTLY_PUTTING 0x800 // 当前处于写操作中
#define _IO_IS_APPENDING      0x1000 // 追加模式（文件打开时指针在末尾）
#define _IO_IS_FILEBUF        0x2000 // 文件缓冲区（非终端或管道）
#define _IO_USER_LOCK 0x8000  // 用户自定义锁（控制并发访问）

```

在执行流程中一般会将 \_flag 和定义常量进行按位与预算，并根据与运算的结构进行判断如何执行：

#### puts() 函数的执行流程

##### `_IO_puts --> _IO_new_file_xsputn`

puts 函数在源码中的表现形式为 \_IO\_puts:

```c
int
_IO_puts (const char *str)
{
    int result = EOF;              // 初始化返回值为 EOF（表示失败）
    size_t len = strlen (str);     // 计算字符串长度（不含 '\0'）
    _IO_acquire_lock (stdout);     // 获取 stdout 的锁（防止并发写入）

    // 检查流的虚表偏移和宽字符模式是否合法
    if ((_IO_vtable_offset (stdout) != 0
       || _IO_fwide (stdout, -1) == -1)  // 确保流处于字节模式（非宽字符）
      && _IO_sputn (stdout, str, len) == len  // 将字符串写入缓冲区
      && _IO_putc_unlocked ('\n', stdout) != EOF)  // 写入换行符
        result = MIN (INT_MAX, len + 1);  // 成功时返回写入字符数（含 '\n'）

    _IO_release_lock (stdout);       // 释放锁
    return result;                   // 返回结果
}

```

这里可以看到 \_IO\_puts 在过程当中调用了一个叫做 \_IO\_sputn 的函数，\[ \_IO\_fwrite 也会调用这个 ]，\_IO\_sputn 其实是一个宏，他的作用就是调用 *IO\_2\_1\_stdout* 中的 vtable 所指向的 \_xsputn，也就是 \_IO\_new\_file\_xsputn 函数。

##### `_IO_new_file_xsputn --> _IO_OVERFLOW`：

```c
size_t
_IO_new_file_xsputn (FILE *f, const void *data, size_t n)
{
    const char *s = (const char *) data;
    size_t to_do = n;
    int must_flush = 0;
    size_t count = 0;

    if (n <= 0)
        return 0;
    /* This is an optimized implementation.
     If the amount to be written straddles a block boundary
     (or the filebuf is unbuffered), use sys_write directly. */

    /* First figure out how much space is available in the buffer. */
    if ((f->_flags & _IO_LINE_BUF) && (f->_flags & _IO_CURRENTLY_PUTTING))
    {
        count = f->_IO_buf_end - f->_IO_write_ptr;
        if (count >= n)
        {
            const char *p;
            for (p = s + n; p > s; )
            {
                if (*--p == '\n')
                {
                    count = p - s + 1;
                    must_flush = 1;
                    break;
                }
            }
        }
    }
    else if (f->_IO_write_end > f->_IO_write_ptr)
        count = f->_IO_write_end - f->_IO_write_ptr; /* Space available. */

    /* Then fill the buffer. */
    if (count > 0)
    {
        if (count > to_do)
            count = to_do;
        f->_IO_write_ptr = __mempcpy (f->_IO_write_ptr, s, count);
        s += count;
        to_do -= count;
    }
    if (to_do + must_flush > 0)
    {
        size_t block_size, do_write;
        /* Next flush the (full) buffer. */
        if (_IO_OVERFLOW (f, EOF) == EOF)
            /* If nothing else has to be written we must not signal the
	   caller that everything has been written.  */
            return to_do == 0 ? EOF : n - to_do;

        /* Try to maintain alignment: write a whole number of blocks.  */
        block_size = f->_IO_buf_end - f->_IO_buf_base;
        do_write = to_do - (block_size >= 128 ? to_do % block_size : 0);

        if (do_write)
        {
            count = new_do_write (f, s, do_write);
            to_do -= count;
            if (count < do_write)
                return n - to_do;
        }

        /* Now write out the remainder.  Normally, this will fit in the
	 buffer, but it's somewhat messier for line-buffered files,
	 so we let _IO_default_xsputn handle the general case. */
        if (to_do)
            to_do -= _IO_default_xsputn (f, s+do_write, to_do);
    }
    return n - to_do;
}


```

首先进入函数之后判断输出缓冲区还有多少空间，这里是由 \_IO\_write\_end - \_IO\_write\_base 得来的，这两个是 FILE 结构体中的两个成员遍历那个，分别是输出结束地址和真实输出地址。

关键代码：

```plain
1335    if (__IO_OVERFLOW (f, EOF) == EOF)
1336      /* If nothing else has to be written we must not signal the 
1337         caller that everything has been written. */
1338      return to_do == 0 ? EOF : n - to_do;
```

经过上述最后一步的判断，如果还有剩余则说明输出缓冲区未建立或者空间已满，那么就需要通过 \_IO\_OVERFLOW 函数来建立或清空缓冲区，这个函数主要是实现刷新缓冲区或建立缓冲区的功能。在 vtable 为 \_overflow

##### `_IO_new_file_overflow --> _IO_do_write`

```c
int
_IO_new_file_overflow (FILE *f, int ch)
{
    if (f->_flags & _IO_NO_WRITES) /* SET ERROR */
    {
        f->_flags |= _IO_ERR_SEEN;
        __set_errno (EBADF);
        return EOF;
    }
    /* If currently reading or no buffer allocated. */
    if ((f->_flags & _IO_CURRENTLY_PUTTING) == 0 || f->_IO_write_base == NULL)
    {
        /* Allocate a buffer if needed. */
        if (f->_IO_write_base == NULL)
        {
            _IO_doallocbuf (f);
            _IO_setg (f, f->_IO_buf_base, f->_IO_buf_base, f->_IO_buf_base);
        }
        /* Otherwise must be currently reading.
	 If _IO_read_ptr (and hence also _IO_read_end) is at the buffer end,
	 logically slide the buffer forwards one block (by setting the
	 read pointers to all point at the beginning of the block).  This
	 makes room for subsequent output.
	 Otherwise, set the read pointers to _IO_read_end (leaving that
	 alone, so it can continue to correspond to the external position). */
        if (__glibc_unlikely (_IO_in_backup (f)))
        {
            size_t nbackup = f->_IO_read_end - f->_IO_read_ptr;
            _IO_free_backup_area (f);
            f->_IO_read_base -= MIN (nbackup,
                               f->_IO_read_base - f->_IO_buf_base);
            f->_IO_read_ptr = f->_IO_read_base;
        }

        if (f->_IO_read_ptr == f->_IO_buf_end)
            f->_IO_read_end = f->_IO_read_ptr = f->_IO_buf_base;
        f->_IO_write_ptr = f->_IO_read_ptr;
        f->_IO_write_base = f->_IO_write_ptr;
        f->_IO_write_end = f->_IO_buf_end;
        f->_IO_read_base = f->_IO_read_ptr = f->_IO_read_end;

        f->_flags |= _IO_CURRENTLY_PUTTING;
        if (f->_mode <= 0 && f->_flags & (_IO_LINE_BUF | _IO_UNBUFFERED))
            f->_IO_write_end = f->_IO_write_ptr;
    }
    if (ch == EOF)
        return _IO_do_write (f, f->_IO_write_base,f->_IO_write_ptr - f->_IO_write_base);
    if (f->_IO_write_ptr == f->_IO_buf_end ) /* Buffer is really full */
        if (_IO_do_flush (f) == EOF)
            return EOF;
    *f->_IO_write_ptr++ = ch;
    if ((f->_flags & _IO_UNBUFFERED)
      || ((f->_flags & _IO_LINE_BUF) && ch == '\n'))
        if (_IO_do_write (f, f->_IO_write_base,
                      f->_IO_write_ptr - f->_IO_write_base) == EOF)
            return EOF;
    return (unsigned char) ch;
}


```

上述代码关键在于 ：

`_IO_do_write (f, f->_IO_write_base,f->_IO_write_ptr - f->_IO_write_base)` ，我们需要成功执行 \_IO\_do\_write()函数，这个函数作用是调用write输出输出缓冲区，传入的参数分别为：stdout结构体、\_IO\_write\_base（输出缓冲区起始地址）和size（\_IO\_write\_end - \_IO\_write\_base计算得来）

这时，我们可以事先在stdout的\_IO\_write\_base的位置部署要输出的起始地址，那么再去利用\_IO\_do\_write函数，即可打印部分内存地址，打印出来的内容就包含我们所需要泄露的libc

#### 为了执行\_IO\_do\_write()函数，我们得绕过前面的检查：

##### 第一个检查：

```c
 if (f->_flags & _IO_NO_WRITES) /* SET ERROR */
    {
      f->_flags |= _IO_ERR_SEEN;
      __set_errno (EBADF);
      return EOF;
    }

```

这里判断 \_flags 的标志位是否包含 \_IO\_NO\_WRITES；

```c
#define _IO_MAGIC 0xFBAD0000 /* 魔数 */
#define _IO_NO_WRITES  8   // 禁止写操作（只读模式）
```

为了通过这个检查，我们将此处的运算计算为假，所以我们只需要将 \_flags 设置为 0xfbad0000 即可 。

```c
_flag=0xFBAD0000 --> 11111011101011010000000000000000 (第三位为0即可)

_IO_NO_WRITES = 8 --> 00000000000000000000000000001000
```

##### 第二个检查：

```c
if ((f->_flags & _IO_CURRENTLY_PUTTING) == 0 || f->_IO_write_base == NULL){...}
```

由于我们会先覆盖 \_IO\_write\_base 的地址，所以 f -> \_IO\_write\_base NULL 必定为假，接下来我们令( f -> \_flags & \_IO\_CURRENTLY\_PUTTING )== 0 为假即可，即设置 \_flags = 0xfbad0800 。

```c

