#define _IO_CURRENTLY_PUTTING 0x800
f->_flags & _IO_CURRENTLY_PUTTING = 1
_flags = 0xfbad0800

```

##### 第三个检查：

```c
  if (ch == EOF)
    return _IO_do_write (f, f->_IO_write_base,f->_IO_write_ptr - f->_IO_write_base);
```

由于前面传进来的参数就是 EOF 所以不需要去管他，在绕过这些检查之后，

我们就成功进入了 \_IO\_do\_write()函数

#### `_IO_new_do_write --> new_do_write`

```c
int
_IO_new_do_write (FILE *fp, const char *data, size_t to_do)
{
  return (to_do == 0
	  || (size_t) new_do_write (fp, data, to_do) == to_do) ? 0 : EOF;
}

```

我们进入 \_IO\_do\_write()函数之后就会进入 \_IO\_new\_do\_write 函数，该函数只是调用了 \_new\_do\_write 函数，参数分别为 stdout 结构体，输出缓冲区其实地址，输出长度

跟进 \_new\_do\_write 函数：

#### `new_do_write --> _IO_SYSWRITE`：

```c
static size_t
new_do_write (FILE *fp, const char *data, size_t to_do)
{
    size_t count;
    if (fp->_flags & _IO_IS_APPENDING)
        /* On a system without a proper O_APPEND implementation,
       you would need to sys_seek(0, SEEK_END) here, but is
       not needed nor desirable for Unix- or Posix-like systems.
       Instead, just indicate that offset (before and after) is
       unpredictable. */
        fp->_offset = _IO_pos_BAD;
    else if (fp->_IO_read_end != fp->_IO_write_base)
    {
        off64_t new_pos
            = _IO_SYSSEEK (fp, fp->_IO_write_base - fp->_IO_read_end, 1);
        if (new_pos == _IO_pos_BAD)
            return 0;
        fp->_offset = new_pos;
    }
    count = _IO_SYSWRITE (fp, data, to_do);
    if (fp->_cur_column && count)
        fp->_cur_column = _IO_adjust_column (fp->_cur_column - 1, data, count) + 1;
    _IO_setg (fp, fp->_IO_buf_base, fp->_IO_buf_base, fp->_IO_buf_base);
    fp->_IO_write_base = fp->_IO_write_ptr = fp->_IO_buf_base;
    fp->_IO_write_end = (fp->_mode <= 0
                       && (fp->_flags & (_IO_LINE_BUF | _IO_UNBUFFERED))
                       ? fp->_IO_buf_base : fp->_IO_buf_end);
    return count;
}

```

<code><font style="background-color:rgba(0, 0, 0, 0.04);">count = _IO_SYSWRITE (fp, data, to_do);</font></code>首先明确目标是进入这个函数，该函数会执行系统调用write。

```c
 if (fp->_flags & _IO_IS_APPENDING)
 else if (fp->_IO_read_end != fp->_IO_write_base)
```

接下来就是考虑这两个判断语句，我们只需要去满足<code> if (fp->_flags & _IO_IS_APPENDING)</code>这个判断语句，去执行 `count = _IO_SYSWRITE (fp, data, to_do);`，因为另一个条件判断绕过是比较难的。

我们只需要将 \_flags 设置为 0xfbad1000 即可

```c

#define _IO_MAGIC 0xFBAD0000
#define _IO_IS_APPENDING 0x1000
fp->_flags & _IO_IS_APPENDING = 1
_flags = 0xfbad1000

```

接下来就可以执行 `_IO_SYSWRITE (fp, data, to_do)`函数打印出我们一开始设置的要输出的起始地址，从而达到泄露libc的目的了。

### 总结：

我们需要满足以下条件来执行`_IO_SYSWRITE (fp, data, to_do)`：

```c

_flags & _IO_NO_WRITES = 0
_flags & _IO_CURRENTLY_PUTTING = 1
_flags & _IO_IS_APPENDING = 1
_flags = 0xFBAD1800

```

* 设置\_IO\_write\_base指向想要泄露的位置，\_IO\_write\_ptr指向泄露结束的地址(不需要一定设置指向结尾，stdout结构中自带地址也足够泄露libc)

整个函数的调用流程：

```c

    _IO_puts 
    -->>_IO_new_file_xsputn 
    -->> _IO_OVERFLOW
    -->> _IO_do_write(_IO_new_do_write) 
    -->> _new_do_write
    -->> _IO_SYSWRITE 

```


